const sampleProductsList=[{id:"101",title:"Premium Cotton Hoodie",price:49.99,image:"https://images.unsplash.com/photo-1556821840-3a63f95609a7?q=80&w=400"},{id:"102",title:"Classic Denim Jacket",price:65,image:"https://images.unsplash.com/photo-1576995853123-5a10305d93c0?q=80&w=400"},{id:"103",title:"Minimalist Leather Watch",price:120,image:"https://images.unsplash.com/photo-1523275335684-37898b6baf30?q=80&w=400"},{id:"104",title:"Athletic Running Sneakers",price:85.5,image:"https://images.unsplash.com/photo-1542291026-7eec264c27ff?q=80&w=400"}];function syncHomepageBadgeText(){let t=document.getElementById("navCartBadge");if(t)try{let e=JSON.parse(localStorage.getItem("cartItemsArray"))||[],a=e.reduce((t,e)=>t+e.quantity,0);t.textContent=a}catch(i){console.error("Failed parsing cart tracking array updates:",i)}}function displayStorefrontProducts(){let t=document.getElementById("products-grid");t&&(t.innerHTML="",sampleProductsList.forEach(e=>{let a=document.createElement("div");a.className="product-card",a.style="background: #fff; border: 1px solid #eee; padding: 15px; border-radius: 8px; box-shadow: 0 2px 5px rgba(0,0,0,0.05);",a.innerHTML=`
            <img src="${e.image}" 
                 loading="lazy" 
                 alt="${e.title}" 
                 style="width: 100%; height: 200px; display: block; object-fit: cover; border-radius: 4px;"
            />
            <h3 style="font-size: 16px; color: #333; margin-top: 12px; margin-bottom: 10px;">${e.title}</h3>
            <p style="color: #ff5722; font-weight: bold; font-size: 18px; margin-bottom: 10px;">$${e.price}</p>
            <a href="./product.html?id=${e.id}" style="display: block; background: #333; color: #fff; text-align: center; padding: 8px; text-decoration: none; border-radius: 4px; font-size: 14px;">View Product</a>
        `,t.appendChild(a)}))}document.addEventListener("DOMContentLoaded",()=>{syncHomepageBadgeText(),displayStorefrontProducts()});const authStateTracker=firebase.auth();function generateOptimizedImage(t,e){let a=`images/${t}-small.webp`,i=`images/${t}-medium.webp`,o=`images/${t}-large.webp`;return`
        <img src="${o}" 
             srcset="${a} 480w, ${i} 800w, ${o} 1200w"
             sizes="(max-width: 600px) 480px, (max-width: 900px) 800px, 1200px"
             loading="lazy" 
             alt="${e}"
             class="product-card-img" 
             style="width: 100%; height: auto; display: block; object-fit: cover;"
        />
    `.trim()}authStateTracker.onAuthStateChanged(t=>{let e=document.querySelector(".nav-actions-container");e&&t&&(e.innerHTML=`
                <span style="font-size: 14px; color: #555; font-weight: 600;">Hi, ${t.email.split("@")[0]}</span>
                <button id="logoutBtn" style="font-size: 15px; font-weight: 600; color: #e53935; background: none; border: 1px solid #e53935; padding: 8px 16px; border-radius: 4px; cursor: pointer; transition: all 0.2s;">
                    <i class="fa-solid fa-arrow-right-from-bracket"></i> Logout
                </button>
                <a href="./cart.html" style="font-size: 15px; font-weight: 600; color: #ff5722; text-decoration: none; border: 1px solid #ff5722; padding: 8px 16px; border-radius: 4px; display: inline-flex; align-items: center; gap: 8px;">
                    <i class="fa-solid fa-basket-shopping"></i> My Cart (<span id="navCartBadge">0</span>)
                </a>
            `,document.getElementById("logoutBtn").addEventListener("click",()=>{firebase.auth().signOut().then(()=>{alert("Logged out successfully."),window.location.reload()})}))});